# ENDPOINTS
# =============================================================================


@app.get("/health", summary="Liveness check")
async def health():
    """Returns 200 OK with service info. No auth required."""
    return {
        "status": "online",
        "message": "Ghost Worker Detection API is live",
        "models": "PAYROLL_SCAN (IsoForest + XGBoost) | RINSE_SCAN (XGBoost)",
        "version": "2.0.0",
        "column_mapping": "Tier1=rapidfuzz (local) | Tier2=Gemini fallback (1 call/file max)",
    }


@app.post("/score", summary="Score a payroll file")
async def score(
    file: UploadFile = File(..., description="Payroll file (.csv / .xlsx / .xls)"),
    import_id: str = Form(default="", description="Client-supplied import identifier"),
    company_name: str = Form(
        default="Unknown Company", description="Organisation name (metadata only)"
    ),
    location: str = Form(
        default="Unknown Location", description="Geographic location (metadata only)"
    ),
    branch_name: str = Form(
        default="Unknown Branch", description="Branch or business unit (metadata only)"
    ),
):
    """Score every employee in the uploaded payroll file.

    Column names in the uploaded file are automatically mapped to the canonical
    schema.  The mapping audit trail is returned in scan_metadata.column_mapping.

    Returns:
        JSON conforming to the Ghost Worker Detection response schema v2.

    Raises:
        400: File missing, unreadable, or unsupported format.
        500: Internal processing error.
    """
    if not file.filename:
        raise HTTPException(status_code=400, detail="No file provided.")

    try:
        content = await file.read()
        df_raw = parse_file(content, file.filename)
        results = await score_payroll(df_raw, import_id=import_id)

        results["company_name"] = company_name
        results["location"] = location
        results["branch_name"] = branch_name

        return results

    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc))
    except Exception as exc:
        raise HTTPException(status_code=500, detail=str(exc))
